mapper.update:
UPDATE assistant_bot_generation_history
SET status = #{status},
    published_post_num = #{publishedPostNum}
WHERE id = #{id}

mapper.select:
SELECT count(*)
FROM assistant_bot_generation_history
WHERE board_title = #{boardTitle}
  AND generation_mode = #{generationMode}
  AND status = 'published'
  AND created_at >= #{since}
